create table rmais_certificado_audit_log (
    id            number,
    action_type   varchar2(10 byte),
    deleted_at    date,
    deleted_by    varchar2(200 byte),
    cert_filename varchar2(1000 byte),
    receiver_name varchar2(120 byte),
    obs           varchar2(2000 byte)
);


